import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaComment, FaHeart, FaRegHeart, FaBookmark, FaRegBookmark, FaShare } from 'react-icons/fa';
import { toast } from 'react-toastify';
import { AuthContext } from '../context/AuthContext';
import forumService from '../services/forumService';
import formatDate from '../utils/formatDate';

// ForumPostCard component for displaying post previews on the Forum page
const ForumPostCard = ({ post, refreshPosts }) => {
  const { user } = useContext(AuthContext);
  const [liked, setLiked] = useState(post.isLiked || false);
  const [likesCount, setLikesCount] = useState(post.likesCount || 0);
  const [bookmarked, setBookmarked] = useState(post.isBookmarked || false);

  // Truncate text if it's too long
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substr(0, maxLength) + '...';
  };

  // Handle like/unlike post
  const handleLikeToggle = async () => {
    if (!user) {
      toast.info('Please log in to like posts');
      return;
    }

    try {
      if (liked) {
        await forumService.unlikePost(post._id);
        setLiked(false);
        setLikesCount(prev => prev - 1);
      } else {
        await forumService.likePost(post._id);
        setLiked(true);
        setLikesCount(prev => prev + 1);
      }
    } catch (error) {
      toast.error('Failed to process like');
      console.error('Error toggling like:', error);
    }
  };

  // Handle bookmark/unbookmark post
  const handleBookmarkToggle = async () => {
    if (!user) {
      toast.info('Please log in to bookmark posts');
      return;
    }

    try {
      if (bookmarked) {
        await forumService.unbookmarkPost(post._id);
        setBookmarked(false);
      } else {
        await forumService.bookmarkPost(post._id);
        setBookmarked(true);
      }
    } catch (error) {
      toast.error('Failed to process bookmark');
      console.error('Error toggling bookmark:', error);
    }
  };

  // Handle share post
  const handleShare = () => {
    if (navigator.share) {
      navigator.share({
        title: post.title,
        text: `Check out this discussion: ${post.title}`,
        url: window.location.origin + `/forum/post/${post._id}`
      })
        .then(() => toast.success('Post shared successfully'))
        .catch((error) => console.error('Error sharing:', error));
    } else {
      // Fallback for browsers that don't support navigator.share
      navigator.clipboard.writeText(window.location.origin + `/forum/post/${post._id}`)
        .then(() => toast.success('Link copied to clipboard'))
        .catch(() => toast.error('Failed to copy link'));
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 transition-transform hover:shadow-lg">
      {/* Post Header */}
      <div className="flex justify-between items-start mb-3">
        <div>
          <Link to={`/forum/post/${post._id}`} className="text-xl font-semibold text-indigo-700 hover:text-indigo-900">
            {post.title}
          </Link>
          <div className="text-sm text-gray-500 mt-1">
            <span className="bg-blue-100 text-blue-800 text-xs font-medium px-2.5 py-0.5 rounded">
              {post.category}
            </span>
            <span className="ml-2">Posted by {post.author?.name || 'Anonymous'} • {formatDate(post.createdAt, { includeRelative: true })}</span>
          </div>
        </div>
      </div>

      {/* Post Content */}
      <div className="mb-4">
        <p className="text-gray-700">{truncateText(post.content)}</p>
        {post.content.length > 150 && (
          <Link to={`/forum/post/${post._id}`} className="text-indigo-600 hover:text-indigo-800 text-sm mt-1 inline-block">
            Read more...
          </Link>
        )}
      </div>

      {/* Post Image (if any) */}
      {post.image && (
        <div className="mb-4">
          <img 
            src={post.image} 
            alt={post.title} 
            className="w-full h-48 object-cover rounded-md" 
          />
        </div>
      )}

      {/* Post Footer - Actions */}
      <div className="flex justify-between text-gray-500 pt-2 border-t">
        <Link to={`/forum/post/${post._id}`} className="flex items-center hover:text-indigo-700">
          <FaComment className="mr-1" />
          <span>{post.commentsCount || 0} Comments</span>
        </Link>
        
        <div className="flex space-x-4">
          <button 
            onClick={handleLikeToggle} 
            className={`flex items-center hover:text-red-500 ${liked ? 'text-red-500' : ''}`}
          >
            {liked ? <FaHeart className="mr-1" /> : <FaRegHeart className="mr-1" />}
            <span>{likesCount}</span>
          </button>
          
          <button 
            onClick={handleBookmarkToggle} 
            className={`flex items-center hover:text-indigo-700 ${bookmarked ? 'text-indigo-700' : ''}`}
          >
            {bookmarked ? <FaBookmark /> : <FaRegBookmark />}
          </button>
          
          <button 
            onClick={handleShare} 
            className="flex items-center hover:text-indigo-700"
          >
            <FaShare />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ForumPostCard;
